+            b'a'..=b'f' => Some(b - b'a' + 10),
+            b'A'..=b'F' => Some(b - b'A' + 10),
+            _ => None,
+        }
+    };
+    let b1 = parse_hex(h1)?;
+    let b2 = parse_hex(h2)?;
